import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => ''),
  mkdirSync: vi.fn(),
  appendFileSync: vi.fn(),
  writeFileSync: vi.fn(),
  readdirSync: vi.fn(() => []),
  unlinkSync: vi.fn(),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { existsSync, readFileSync, appendFileSync, readdirSync, unlinkSync } from 'node:fs';
import { nudgeOutcomeResolver } from '../../lifecycle/nudge-outcome-resolver.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

const PROJECT_DIR = '/test/project';

function input(): HookInput {
  return { tool_name: 'SessionStart', session_id: 'sess-current', tool_input: {} };
}

function setMarkers(markers: Record<string, { firedAt: string; resolved: boolean }>): void {
  vi.mocked(existsSync).mockImplementation(((p: unknown) => {
    const s = String(p);
    if (s.endsWith('/state')) return true;
    const m = s.match(/nudge-outcome-(.+)\.json$/);
    return m ? m[1] in markers : false;
  }) as unknown as typeof existsSync);

  vi.mocked(readdirSync).mockReturnValue(
    Object.keys(markers).map(sid => `nudge-outcome-${sid}.json`) as never,
  );

  vi.mocked(readFileSync).mockImplementation(((p: unknown) => {
    const m = String(p).match(/nudge-outcome-(.+)\.json$/);
    if (m && markers[m[1]]) {
      return JSON.stringify({
        sessionId: m[1],
        firedAt: markers[m[1]].firedAt,
        resolved: markers[m[1]].resolved,
      });
    }
    return '';
  }) as unknown as typeof readFileSync);
}

describe('nudgeOutcomeResolver', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    ctx = createTestContext({ projectDir: PROJECT_DIR, sessionId: 'sess-current' });
  });

  it('returns silent when no markers', () => {
    vi.mocked(existsSync).mockReturnValue(false);
    const result = nudgeOutcomeResolver(input(), ctx);
    expect(result.continue).toBe(true);
    expect(appendFileSync).not.toHaveBeenCalled();
  });

  it('records "clear" when prior nudge < 24h ago', () => {
    const tenMinAgo = new Date(Date.now() - 10 * 60_000).toISOString();
    setMarkers({ 'sess-prior': { firedAt: tenMinAgo, resolved: false } });

    nudgeOutcomeResolver(input(), ctx);

    expect(appendFileSync).toHaveBeenCalled();
    const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
    expect(body.user_action).toBe('clear');
    expect(body.nudge_session_id).toBe('sess-prior');
    expect(body.type).toBe('outcome');
    expect(unlinkSync).toHaveBeenCalled();
  });

  it('records "ignored" when prior nudge >= 24h ago', () => {
    const twoDaysAgo = new Date(Date.now() - 2 * 24 * 60 * 60_000).toISOString();
    setMarkers({ 'sess-old': { firedAt: twoDaysAgo, resolved: false } });

    nudgeOutcomeResolver(input(), ctx);

    const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
    expect(body.user_action).toBe('ignored');
  });

  it('skips current-session marker (PostCompact owns that case)', () => {
    const tenMinAgo = new Date(Date.now() - 10 * 60_000).toISOString();
    setMarkers({ 'sess-current': { firedAt: tenMinAgo, resolved: false } });

    nudgeOutcomeResolver(input(), ctx);

    expect(appendFileSync).not.toHaveBeenCalled();
  });

  it('skips already-resolved markers', () => {
    const tenMinAgo = new Date(Date.now() - 10 * 60_000).toISOString();
    setMarkers({ 'sess-done': { firedAt: tenMinAgo, resolved: true } });

    nudgeOutcomeResolver(input(), ctx);

    expect(appendFileSync).not.toHaveBeenCalled();
  });

  it('handles invalid firedAt by deleting the marker', () => {
    setMarkers({ 'sess-bad': { firedAt: 'not-a-date', resolved: false } });

    nudgeOutcomeResolver(input(), ctx);

    expect(unlinkSync).toHaveBeenCalled();
    expect(appendFileSync).not.toHaveBeenCalled();
  });

  it('processes mixed batch: clear + ignored', () => {
    const recent = new Date(Date.now() - 60_000).toISOString();
    const old = new Date(Date.now() - 25 * 60 * 60_000).toISOString();
    setMarkers({
      'sess-recent': { firedAt: recent, resolved: false },
      'sess-stale': { firedAt: old, resolved: false },
    });

    nudgeOutcomeResolver(input(), ctx);

    expect(appendFileSync).toHaveBeenCalledTimes(2);
    const actions = vi.mocked(appendFileSync).mock.calls.map(c => JSON.parse(String(c[1]).trim()).user_action);
    expect(actions.sort()).toEqual(['clear', 'ignored']);
  });
});
